REMEDY_MAP = {
    "Apple___Apple_scab":{"en":"1. Remove and destroy infected leaves immediately.\n2. Apply fungicide (captan or myclobutanil) every 7–10 days.\n3. Avoid overhead irrigation.\n4. Prune trees to improve air circulation.\n5. Rake fallen leaves in autumn.","hi":"1. संक्रमित पत्तियों को तुरंत हटाकर नष्ट करें।\n2. हर 7–10 दिन में कैप्टन या माइक्लोब्यूटानिल फफूंदनाशक छिड़कें।\n3. ऊपर से पानी देने से बचें।\n4. वायु संचार के लिए छंटाई करें।\n5. गिरी पत्तियां हटाएं।"},
    "Apple___Black_rot":{"en":"1. Prune and destroy all dead or diseased wood.\n2. Remove mummified fruits.\n3. Apply copper-based fungicide every 10 days.\n4. Ensure good drainage.\n5. Disinfect pruning tools with 10% bleach.","hi":"1. सभी मृत लकड़ी को काटकर नष्ट करें।\n2. सूखे फलों को हटाएं।\n3. हर 10 दिन में ताम्र फफूंदनाशक लगाएं।\n4. जल निकासी सुनिश्चित करें।\n5. औजारों को कीटाणुमुक्त करें।"},
    "Apple___Cedar_apple_rust":{"en":"1. Apply myclobutanil fungicide at pink bud stage.\n2. Remove nearby juniper trees if possible.\n3. Spray every 7–10 days during wet spring.\n4. Plant rust-resistant varieties next season.","hi":"1. गुलाबी कली अवस्था में माइक्लोब्यूटानिल लगाएं।\n2. पास के जुनिपर हटाएं।\n3. गीले वसंत में हर 7–10 दिन छिड़काव करें।\n4. रोग-प्रतिरोधी किस्में लगाएं।"},
    "Apple___healthy":{"en":"✅ Apple plant is healthy!\n1. Water regularly at the base.\n2. Annual pruning for air circulation.\n3. Balanced NPK fertiliser in spring.\n4. Inspect leaves weekly.","hi":"✅ सेब का पौधा स्वस्थ है!\n1. जड़ के पास नियमित पानी दें।\n2. वार्षिक छंटाई करें।\n3. वसंत में संतुलित उर्वरक दें।\n4. साप्ताहिक जांच करें।"},
    "Blueberry___healthy":{"en":"✅ Blueberry is healthy!\n1. Maintain soil pH 4.5–5.5.\n2. Mulch with pine needles.\n3. Prune old canes after harvest.\n4. Use ammonium sulphate for nitrogen.","hi":"✅ ब्लूबेरी स्वस्थ है!\n1. मिट्टी pH 4.5–5.5 रखें।\n2. पाइन सुइयों से मल्च करें।\n3. कटाई के बाद छंटाई करें।\n4. अमोनियम सल्फेट उर्वरक उपयोग करें।"},
    "Cherry_(including_sour)___Powdery_mildew":{"en":"1. Apply sulphur fungicide at first sign of white powder.\n2. Remove and burn infected shoots.\n3. Avoid excess nitrogen.\n4. Prune for air circulation.\n5. Water in the morning.","hi":"1. सफेद पाउडर पर सल्फर फफूंदनाशक लगाएं।\n2. संक्रमित टहनियां जलाएं।\n3. अत्यधिक नाइट्रोजन से बचें।\n4. छंटाई करें।\n5. सुबह पानी दें।"},
    "Cherry_(including_sour)___healthy":{"en":"✅ Cherry is healthy!\n1. Water deeply but infrequently.\n2. Fertilise after harvest.\n3. Watch for aphids — treat with neem oil.\n4. Net tree to protect from birds.","hi":"✅ चेरी स्वस्थ है!\n1. गहराई से पानी दें।\n2. कटाई के बाद उर्वरक दें।\n3. एफिड पर नीम तेल लगाएं।\n4. जाल लगाएं।"},
    "Corn_(maize)___Cercospora_leaf_spot Gray_leaf_spot":{"en":"1. Apply strobilurin or triazole fungicide.\n2. Rotate crops — avoid maize consecutively.\n3. Till crop debris after harvest.\n4. Plant resistant hybrids next season.","hi":"1. स्ट्रोबिलुरिन या ट्रायज़ोल फफूंदनाशक लगाएं।\n2. फसल चक्र अपनाएं।\n3. कटाई के बाद अवशेष मिलाएं।\n4. प्रतिरोधी किस्में लगाएं।"},
    "Corn_(maize)___Common_rust_":{"en":"1. Apply mancozeb or propiconazole fungicide.\n2. Plant rust-resistant varieties.\n3. Avoid late planting.\n4. Remove heavily infected plants.\n5. Monitor weekly in humid conditions.","hi":"1. मैन्कोज़ेब या प्रोपिकोनाज़ोल लगाएं।\n2. रतुआ-प्रतिरोधी किस्में लगाएं।\n3. देर से बुवाई से बचें।\n4. संक्रमित पौधे हटाएं।\n5. साप्ताहिक निगरानी करें।"},
    "Corn_(maize)___Northern_Leaf_Blight":{"en":"1. Apply propiconazole at first sign of lesions.\n2. Use certified disease-free seed.\n3. Rotate crops with non-host plants.\n4. Remove crop debris after harvest.\n5. Plant tolerant hybrids.","hi":"1. घाव पर प्रोपिकोनाज़ोल लगाएं।\n2. प्रमाणित बीज उपयोग करें।\n3. फसल चक्र अपनाएं।\n4. अवशेष हटाएं।\n5. सहिष्णु किस्में लगाएं।"},
    "Corn_(maize)___healthy":{"en":"✅ Maize is healthy!\n1. Maintain soil moisture.\n2. Nitrogen top-dressing at knee-high stage.\n3. Control weeds early.\n4. Scout weekly for pests.","hi":"✅ मक्का स्वस्थ है!\n1. नमी बनाए रखें।\n2. नाइट्रोजन टॉप-ड्रेसिंग करें।\n3. खरपतवार नियंत्रण करें।\n4. साप्ताहिक जांच करें।"},
    "Grape___Black_rot":{"en":"1. Apply myclobutanil from bud break through mid-summer.\n2. Remove mummified berries and infected leaves.\n3. Prune vines for air circulation.\n4. Use drip irrigation only.\n5. Remove wild grapes nearby.","hi":"1. कली से मध्य-गर्मी तक माइक्लोब्यूटानिल लगाएं।\n2. सूखे जामुन और संक्रमित पत्तियां हटाएं।\n3. बेलों की छंटाई करें।\n4. ड्रिप सिंचाई उपयोग करें।\n5. पास के जंगली अंगूर हटाएं।"},
    "Grape___Esca_(Black_Measles)":{"en":"1. No cure — focus on prevention.\n2. Seal pruning wounds with wound paste.\n3. Remove and destroy infected wood.\n4. Reduce plant stress with proper irrigation.","hi":"1. कोई उपचार नहीं — रोकथाम करें।\n2. छंटाई घावों पर पेस्ट लगाएं।\n3. संक्रमित लकड़ी हटाएं।\n4. उचित सिंचाई से तनाव कम करें।"},
    "Grape___Leaf_blight_(Isariopsis_Leaf_Spot)":{"en":"1. Apply copper fungicide at first symptom.\n2. Remove infected leaves.\n3. Improve drainage and air circulation.\n4. Apply preventive sprays in wet weather.","hi":"1. पहले लक्षण पर ताम्र फफूंदनाशक लगाएं।\n2. संक्रमित पत्तियां हटाएं।\n3. जल निकासी सुधारें।\n4. बरसाती मौसम में निवारक छिड़काव करें।"},
    "Grape___healthy":{"en":"✅ Grape vines are healthy!\n1. Train on trellis for sun exposure.\n2. Fertilise in spring before bud break.\n3. Thin clusters at fruit set.\n4. Monitor for mealybugs.","hi":"✅ अंगूर की बेलें स्वस्थ हैं!\n1. ट्रेलिस पर लगाएं।\n2. वसंत में उर्वरक दें।\n3. गुच्छे पतले करें।\n4. मीलीबग की निगरानी करें।"},
    "Orange___Haunglongbing_(Citrus_greening)":{"en":"⚠️ WARNING: No cure for Citrus Greening!\n1. Remove and destroy infected trees immediately.\n2. Control psyllid insects with insecticides.\n3. Use certified disease-free nursery plants.\n4. Report to local agriculture department.","hi":"⚠️ चेतावनी: सिट्रस ग्रीनिंग का कोई इलाज नहीं!\n1. संक्रमित पेड़ तुरंत हटाएं।\n2. कीटनाशकों से सिला नियंत्रित करें।\n3. प्रमाणित पौधे उपयोग करें।\n4. कृषि विभाग को सूचित करें।"},
    "Peach___Bacterial_spot":{"en":"1. Apply copper hydroxide spray during dormancy.\n2. Avoid overhead irrigation.\n3. Prune to improve air flow.\n4. Remove infected fruit and leaves.\n5. Plant tolerant varieties next season.","hi":"1. निष्क्रियता में कॉपर हाइड्रॉक्साइड छिड़कें।\n2. ऊपर से सिंचाई से बचें।\n3. वायु प्रवाह के लिए छंटाई करें।\n4. संक्रमित फल और पत्तियां हटाएं।\n5. सहिष्णु किस्में लगाएं।"},
    "Peach___healthy":{"en":"✅ Peach tree is healthy!\n1. Thin fruits for larger peaches.\n2. Apply balanced fertiliser in spring.\n3. Watch for leaf curl in spring.\n4. Irrigate during fruit development.","hi":"✅ आड़ू का पेड़ स्वस्थ है!\n1. फल पतले करें।\n2. वसंत में उर्वरक दें।\n3. पत्ती कर्ल पर नजर रखें।\n4. फल विकास में सिंचाई करें।"},
    "Pepper,_bell___Bacterial_spot":{"en":"1. Apply copper bactericide every 5–7 days in wet weather.\n2. Use certified disease-free seed.\n3. Use drip irrigation only.\n4. Rotate crops for 2 years.\n5. Remove infected plant debris.","hi":"1. गीले मौसम में हर 5–7 दिन ताम्र जीवाणुनाशक लगाएं।\n2. प्रमाणित बीज उपयोग करें।\n3. ड्रिप सिंचाई उपयोग करें।\n4. 2 साल फसल चक्र अपनाएं।\n5. अवशेष हटाएं।"},
    "Pepper,_bell___healthy":{"en":"✅ Bell pepper is healthy!\n1. Provide 6–8 hours of full sun daily.\n2. Water consistently.\n3. Apply calcium to prevent blossom end rot.\n4. Support with stakes when tall.","hi":"✅ शिमला मिर्च स्वस्थ है!\n1. 6–8 घंटे धूप दें।\n2. नियमित पानी दें।\n3. कैल्शियम दें।\n4. डंडे से सहारा दें।"},
    "Potato___Early_blight":{"en":"1. Apply mancozeb or chlorothalonil every 7 days.\n2. Remove lower infected leaves early.\n3. Water at the base only.\n4. Use certified disease-free seed potatoes.\n5. Rotate crops for 3 years.","hi":"1. हर 7 दिन में मैन्कोज़ेब या क्लोरोथैलोनिल लगाएं।\n2. निचली पत्तियां जल्दी हटाएं।\n3. जड़ पर ही पानी दें।\n4. प्रमाणित बीज आलू उपयोग करें।\n5. 3 साल फसल चक्र अपनाएं।"},
    "Potato___Late_blight":{"en":"⚠️ URGENT: Late blight spreads fast!\n1. Apply metalaxyl + mancozeb immediately.\n2. Remove and destroy infected plants.\n3. Do not irrigate in the evening.\n4. Hill up potatoes.\n5. Harvest early if severe.","hi":"⚠️ तत्काल: पछेती झुलसा तेजी से फैलता है!\n1. तुरंत मेटालैक्सिल + मैन्कोज़ेब लगाएं।\n2. संक्रमित पौधे हटाकर नष्ट करें।\n3. शाम को सिंचाई न करें।\n4. मिट्टी चढ़ाएं।\n5. गंभीर हो तो जल्दी काटें।"},
    "Potato___healthy":{"en":"✅ Potato crop is healthy!\n1. Hill soil when plants reach 20 cm.\n2. Water regularly.\n3. Apply potassium fertiliser.\n4. Scout weekly for potato beetle.","hi":"✅ आलू की फसल स्वस्थ है!\n1. 20 सेमी पर मिट्टी चढ़ाएं।\n2. नियमित पानी दें।\n3. पोटेशियम उर्वरक लगाएं।\n4. साप्ताहिक जांच करें।"},
    "Raspberry___healthy":{"en":"✅ Raspberry is healthy!\n1. Cut all fruited canes after harvest.\n2. Apply fertiliser in early spring.\n3. Mulch to conserve moisture.\n4. Trellis canes for support.","hi":"✅ रास्पबेरी स्वस्थ है!\n1. कटाई के बाद सभी शाखाएं काटें।\n2. वसंत में उर्वरक दें।\n3. मल्च करें।\n4. ट्रेलिस से सहारा दें।"},
    "Soybean___healthy":{"en":"✅ Soybean is healthy!\n1. Inoculate seed with Rhizobium.\n2. Maintain soil pH 6.0–6.5.\n3. Scout for aphid and caterpillars.\n4. Ensure good drainage.","hi":"✅ सोयाबीन स्वस्थ है!\n1. राइजोबियम से बीज टीका लगाएं।\n2. pH 6.0–6.5 बनाए रखें।\n3. एफिड जांच करें।\n4. जलभराव से बचें।"},
    "Squash___Powdery_mildew":{"en":"1. Apply neem oil or potassium bicarbonate at first sign.\n2. Remove heavily infected leaves.\n3. Space plants adequately for air circulation.\n4. Water at the base.\n5. Plant mildew-resistant varieties next season.","hi":"1. पहले लक्षण पर नीम तेल छिड़कें।\n2. संक्रमित पत्तियां हटाएं।\n3. पौधों में दूरी रखें।\n4. जड़ पर पानी दें।\n5. प्रतिरोधी किस्में लगाएं।"},
    "Strawberry___Leaf_scorch":{"en":"1. Apply captan fungicide every 10–14 days.\n2. Remove infected leaves.\n3. Renovate beds after fruiting.\n4. Avoid overhead irrigation.\n5. Plant certified disease-free runners.","hi":"1. हर 10–14 दिन में कैप्टन फफूंदनाशक लगाएं।\n2. संक्रमित पत्तियां हटाएं।\n3. फलने के बाद बेड नवीनीकृत करें।\n4. ऊपर से सिंचाई से बचें।\n5. प्रमाणित रनर लगाएं।"},
    "Strawberry___healthy":{"en":"✅ Strawberry is healthy!\n1. Mulch with straw.\n2. Remove runners.\n3. Fertilise after first harvest.\n4. Renew plants every 3 years.","hi":"✅ स्ट्रॉबेरी स्वस्थ है!\n1. पुआल से मल्च करें।\n2. रनर हटाएं।\n3. पहली कटाई के बाद उर्वरक दें।\n4. हर 3 साल नवीनीकृत करें।"},
    "Tomato___Bacterial_spot":{"en":"1. Apply copper hydroxide every 5–7 days.\n2. Avoid working in field when plants are wet.\n3. Use drip irrigation.\n4. Remove and destroy heavily infected plants.\n5. Use disease-free transplants next season.","hi":"1. हर 5–7 दिन कॉपर हाइड्रॉक्साइड लगाएं।\n2. गीले पौधों पर काम न करें।\n3. ड्रिप सिंचाई उपयोग करें।\n4. संक्रमित पौधे हटाएं।\n5. अगले सीजन रोगमुक्त पौध उपयोग करें।"},
    "Tomato___Early_blight":{"en":"1. Apply chlorothalonil or mancozeb every 7 days.\n2. Remove lower leaves touching soil.\n3. Stake or cage tomatoes.\n4. Mulch heavily.\n5. Rotate crops for 2 years.","hi":"1. हर 7 दिन क्लोरोथैलोनिल या मैन्कोज़ेब लगाएं।\n2. मिट्टी छूने वाली पत्तियां हटाएं।\n3. डंडा या पिंजरा लगाएं।\n4. मल्चिंग करें।\n5. 2 साल फसल चक्र अपनाएं।"},
    "Tomato___Late_blight":{"en":"⚠️ URGENT: Spreads extremely fast!\n1. Apply metalaxyl fungicide immediately.\n2. Remove and destroy infected plants.\n3. Do not water in the evening.\n4. Do not compost infected material.\n5. Alert neighbouring farmers.","hi":"⚠️ तत्काल: बहुत तेज फैलता है!\n1. तुरंत मेटालैक्सिल लगाएं।\n2. संक्रमित पौधे तुरंत हटाएं।\n3. शाम को पानी न दें।\n4. खाद न बनाएं।\n5. पड़ोसी किसानों को सचेत करें।"},
    "Tomato___Leaf_Mold":{"en":"1. Apply chlorothalonil or mancozeb.\n2. Reduce humidity and improve ventilation.\n3. Remove infected lower leaves.\n4. Avoid overhead irrigation.\n5. Plant resistant varieties.","hi":"1. क्लोरोथैलोनिल या मैन्कोज़ेब लगाएं।\n2. आर्द्रता कम करें।\n3. निचली पत्तियां हटाएं।\n4. ऊपर से सिंचाई से बचें।\n5. प्रतिरोधी किस्में लगाएं।"},
    "Tomato___Septoria_leaf_spot":{"en":"1. Apply mancozeb or copper every 7–10 days.\n2. Remove infected leaves from the bottom.\n3. Avoid splashing water on leaves.\n4. Mulch soil surface.\n5. Rotate crops for 2 years.","hi":"1. हर 7–10 दिन मैन्कोज़ेब या कॉपर लगाएं।\n2. नीचे से पत्तियां हटाएं।\n3. पत्तियों पर छींटे न पड़ने दें।\n4. मल्च करें।\n5. 2 साल फसल चक्र अपनाएं।"},
    "Tomato___Spider_mites Two-spotted_spider_mite":{"en":"1. Spray with strong water jets to dislodge mites.\n2. Apply neem oil or insecticidal soap every 5–7 days.\n3. Introduce predatory mites.\n4. Avoid over-fertilising with nitrogen.\n5. Keep plants well-watered.","hi":"1. तेज पानी की धार से माइट्स हटाएं।\n2. हर 5–7 दिन नीम तेल या साबुन लगाएं।\n3. शिकारी माइट्स लाएं।\n4. नाइट्रोजन अधिक न दें।\n5. अच्छी तरह पानी दें।"},
    "Tomato___Target_Spot":{"en":"1. Apply azoxystrobin or chlorothalonil.\n2. Remove and destroy lower infected leaves.\n3. Prune suckers for air circulation.\n4. Avoid overhead irrigation.\n5. Rotate with non-solanaceous crops.","hi":"1. एज़ोक्सीस्ट्रोबिन या क्लोरोथैलोनिल लगाएं।\n2. संक्रमित पत्तियां हटाएं।\n3. सकर काटें।\n4. ऊपर से सिंचाई से बचें।\n5. फसल चक्र अपनाएं।"},
    "Tomato___Tomato_Yellow_Leaf_Curl_Virus":{"en":"⚠️ No cure — remove infected plants immediately.\n1. Control whitefly with imidacloprid.\n2. Use reflective silver mulch.\n3. Install yellow sticky traps.\n4. Plant TY resistant varieties.","hi":"⚠️ कोई इलाज नहीं — संक्रमित पौधे तुरंत हटाएं।\n1. इमिडाक्लोप्रिड से सफेद मक्खी नियंत्रित करें।\n2. चांदी मल्च उपयोग करें।\n3. पीले जाल लगाएं।\n4. TY प्रतिरोधी किस्में लगाएं।"},
    "Tomato___Tomato_mosaic_virus":{"en":"⚠️ No chemical cure — remove infected plants.\n1. Wash hands and disinfect tools before handling.\n2. Control aphids and thrips.\n3. Use resistant varieties next season.\n4. Avoid tobacco products near plants.","hi":"⚠️ कोई रासायनिक उपचार नहीं — संक्रमित पौधे हटाएं।\n1. हाथ धोएं और औजार कीटाणुमुक्त करें।\n2. एफिड और थ्रिप्स नियंत्रित करें।\n3. प्रतिरोधी किस्में उपयोग करें।\n4. तंबाकू से बचें।"},
    "Tomato___healthy":{"en":"✅ Tomato is healthy!\n1. Water 2–3 times a week at the base.\n2. Prune suckers for air flow.\n3. Apply calcium fertiliser.\n4. Support with stakes as it grows.","hi":"✅ टमाटर स्वस्थ है!\n1. सप्ताह में 2–3 बार जड़ में पानी दें।\n2. सकर काटें।\n3. कैल्शियम उर्वरक दें।\n4. डंडे से सहारा दें।"},
}

